/**
 * Mock Parity Test
 *
 * Verifies that mock factories export every function from the real common.js.
 * If common.ts adds a new export, this test fails — forcing the mock to be updated.
 * This prevents the silent mock drift that caused 10 CI failures in v7.0.0.
 */

import { describe, it, expect } from 'vitest';
import type { HookResult } from '../../types.js';
import { mockCommonBasic, mockCommonReal } from './mock-common.js';

describe('mock-common parity with real common.js', () => {
  it('mockCommonBasic exports every function from common.js', async () => {
    const real = await import('../../lib/common.js');
    const mock = mockCommonBasic();

    const realExports = Object.keys(real).sort();
    const mockExports = Object.keys(mock).sort();

    const missing = realExports.filter(k => !mockExports.includes(k));

    expect(missing).toEqual([]);
  });

  it('mockCommonReal exports every function from common.js', async () => {
    const real = await import('../../lib/common.js');
    const mock = await mockCommonReal();

    const realExports = Object.keys(real).sort();
    const mockExports = Object.keys(mock).sort();

    const missing = realExports.filter(k => !mockExports.includes(k));

    expect(missing).toEqual([]);
  });

  it('mockCommonBasic output helpers return correct shapes', () => {
    const mock = mockCommonBasic() as Record<string, (...args: string[]) => HookResult>;

    // outputPromptContext must return hookSpecificOutput.additionalContext, NOT systemMessage
    const promptResult = mock.outputPromptContext('test context');
    expect(promptResult.hookSpecificOutput?.additionalContext).toBe('test context');
    expect(promptResult).not.toHaveProperty('systemMessage');
    expect(promptResult.hookSpecificOutput?.hookEventName).toBe('UserPromptSubmit');

    // outputWithContext must return PostToolUse
    const postResult = mock.outputWithContext('post context');
    expect(postResult.hookSpecificOutput?.additionalContext).toBe('post context');
    expect(postResult.hookSpecificOutput?.hookEventName).toBe('PostToolUse');

    // outputBlock must return continue: false
    const blockResult = mock.outputBlock('blocked');
    expect(blockResult.continue).toBe(false);
    expect(blockResult.stopReason).toBe('blocked');

    // outputSilentSuccess must return continue: true, suppressOutput: true
    const silentResult = mock.outputSilentSuccess();
    expect(silentResult.continue).toBe(true);
    expect(silentResult.suppressOutput).toBe(true);

    // outputAllowWithContext must return permissionDecision: allow
    const allowResult = mock.outputAllowWithContext('ctx');
    expect(allowResult.hookSpecificOutput?.permissionDecision).toBe('allow');
    expect(allowResult.hookSpecificOutput?.additionalContext).toBe('ctx');
  });
});
